/**
 * Error surfaced across the FFI boundary to Kotlin/Swift.
 */
sealed class ProverException: kotlin.Exception() {
    
    class Failed(
        
        val `msg`: kotlin.String
        ) : ProverException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<ProverException> {
        override fun lift(error_buf: RustBuffer.ByValue): ProverException = FfiConverterTypeProverError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeProverError : FfiConverterRustBuffer<ProverException> {
    override fun read(buf: ByteBuffer): ProverException {
        

        return when(buf.getInt()) {
            1 -> ProverException.Failed(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: ProverException): ULong {
        return when(value) {
            is ProverException.Failed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
        }
    }

    override fun write(value: ProverException, buf: ByteBuffer) {
        when(value) {
            is ProverException.Failed -> {
                buf.putInt(1)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




